DECLARE
  v_name EMP.ENAME%TYPE;
BEGIN
  SELECT ENAME INTO v_name FROM EMP WHERE EMPNO = 9999;
  DBMS_OUTPUT.PUT_LINE(v_name);
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('Error: Employee not found.');
END;

DECLARE
  v_name EMP.ENAME%TYPE;
BEGIN
  SELECT ENAME INTO v_name FROM EMP;
  DBMS_OUTPUT.PUT_LINE(v_name);
EXCEPTION
  WHEN TOO_MANY_ROWS THEN
    DBMS_OUTPUT.PUT_LINE('Error: Single row expected but multiple rows returned.');
END;

DECLARE
  num1 NUMBER := 10;
  num2 NUMBER := 0;
  result NUMBER;
BEGIN
  result := num1 / num2;
  DBMS_OUTPUT.PUT_LINE(result);
EXCEPTION
  WHEN ZERO_DIVIDE THEN
    DBMS_OUTPUT.PUT_LINE('Error: Division by zero is not allowed.');
END;

DECLARE
  v_str VARCHAR2(2);
BEGIN
  v_str := 'HELLO';
  DBMS_OUTPUT.PUT_LINE(v_str);
EXCEPTION
  WHEN VALUE_ERROR THEN
    DBMS_OUTPUT.PUT_LINE('Error: Value too large for the variable size.');
END;

DECLARE
  v_sal NUMBER;
BEGIN
  SELECT SAL INTO v_sal FROM EMP WHERE ENAME = 'KING';
  v_sal := v_sal / 0;
EXCEPTION
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('An unexpected error occurred.');
END;

