DECLARE
  v_sal NUMBER := 1500;
BEGIN
  IF v_sal < 2000 THEN
    RAISE_APPLICATION_ERROR(-20001, 'Salary must be at least 2000.');
  END IF;
END;

DECLARE
  v_age NUMBER := 16;
BEGIN
  IF v_age < 18 THEN
    RAISE_APPLICATION_ERROR(-20002, 'Underage: Employees must be 18 or older.');
  END IF;
END;

DECLARE
  v_job VARCHAR2(20) := 'CLERK';
BEGIN
  IF v_job = 'CLERK' THEN
    RAISE_APPLICATION_ERROR(-20003, 'Updates are not permitted for Clerk roles.');
  END IF;
END;

DECLARE
  v_deptno NUMBER := 99;
  v_count NUMBER;
BEGIN
  SELECT COUNT(*) INTO v_count FROM DEPT WHERE DEPTNO = v_deptno;
  IF v_count = 0 THEN
    RAISE_APPLICATION_ERROR(-20004, 'Invalid Department ID entered.');
  END IF;
END;
